// NURSING COUNCIL EXAM SITE
// ════════════════════════════════════════════════════════════════════════════

// ── Admin: Daily Mock Manager ─────────────────────────────────────────────
// Admin adds/deletes questions. All questions (up to 250) are served per mock.
// Uses chunked Firestore storage to bypass the 1 MB document limit.

// ── ROBUST QUESTION PARSER ─────────────────────────────────────────────────
// Handles: numbered (1. 2. 3.), Q: format, with/without blank lines,
// inline Answer: lines, and a separate answer-key column.
function robustParseQuestions(pasteText, pasteAnswers) {
  const text = (pasteText||"").trim();
  const ansLines = (pasteAnswers||"").trim().split("\n").map(l=>l.trim()).filter(Boolean);
  if (!text) return [];

  const lines = text.split("\n");
  const blocks = [];
  let cur = [];

  // Detect the start of a new question
  const isQStart = (line) =>
    /^\d{1,3}[\.\)]\s+\S/.test(line) ||          // "1. text" / "1) text"
    /^Q\s*\d*\s*[:\.\-]\s*\S/i.test(line) ||     // "Q:" / "Q1:" / "Q 1."
    /^Question\s*\d*\s*[:\.\-]\s*\S/i.test(line);// "Question 1:"

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) { if (cur.length) cur.push(""); continue; }

    if (isQStart(line) && cur.length > 0) {
      // End current block if it already has option lines or an answer
      const hasOpts = cur.some(l => /^[A-D][\.\)\s:]/i.test(l));
      const hasAns  = cur.some(l => /^(?:ans|answer)\s*[:\.\)]/i.test(l));
      if (hasOpts || hasAns) { blocks.push([...cur]); cur = []; }
    }
    cur.push(line);
    // End block immediately after an inline answer line
    if (/^(?:ANS(?:WER)?)\s*[:\.\)]\s*[A-D]/i.test(line)) {
      blocks.push([...cur]); cur = [];
    }
  }
  if (cur.some(l=>l.trim())) blocks.push(cur);

  return blocks.map((blockLines, idx) => {
    const clean = blockLines.map(l=>l.trim()).filter(Boolean);
    let q = "", options = ["","","",""], ans = 0;
    let qLines = [], inQ = true;

    clean.forEach(line => {
      // Inline answer: "Answer: B" / "ANS: B" / "Ans: B"
      const ansM = line.match(/^(?:ANS(?:WER)?)\s*[:\.\)]\s*([A-D])/i);
      if (ansM) { ans = "ABCD".indexOf(ansM[1].toUpperCase()); if(ans<0) ans=0; inQ=false; return; }

      // Option line: "A. text" / "A) text" / "A: text" / "(A) text"
      const optM = line.match(/^\(?([A-D])\)?[\.\)\s:]\s*(.+)$/i);
      if (optM) {
        const idx2 = "ABCD".indexOf(optM[1].toUpperCase());
        if (idx2 >= 0) { options[idx2] = optM[2].trim(); inQ = false; return; }
      }

      // "Q: text" or "Q1: text" prefix — strip prefix, rest is question
      const qM = line.match(/^(?:Q\s*\d*\s*[:\.\-]|Question\s*\d*\s*[:\.\-])\s*(.+)$/i);
      if (qM) { qLines.push(qM[1].trim()); inQ = true; return; }

      // "1. text" / "1) text" — strip number
      const numM = line.match(/^\d{1,3}[\.\)]\s+(.+)$/);
      if (numM && inQ) { qLines.push(numM[1].trim()); return; }

      if (inQ) qLines.push(line);
    });

    q = qLines.join(" ").trim();

    // Use separate answer column if provided and no inline answer was found
    if (ansLines[idx]) {
      const a = "ABCD".indexOf(ansLines[idx][0]?.toUpperCase());
      if (a >= 0) ans = a;
    }

    return { id: Date.now()+idx, q, options, ans, cat: "General" };
  }).filter(item => item.q && item.options.some(o => o));
}

function AdminDailyMockManager({ toast }) {
  const [pool, setPool] = useSharedData("nv-daily-mock", []);
  const [mockTitle, setMockTitle] = useState(()=>ls("nv-daily-mock-title",""));
  const [saving, setSaving] = useState(false);
  const [mode, setMode] = useState("single"); // "single"|"paste"
  const [form, setForm] = useState({q:"", options:["","","",""], ans:0, cat:"General"});
  const [editIdx, setEditIdx] = useState(null);
  const [pasteText, setPasteText] = useState("");
  const [pasteAnswers, setPasteAnswers] = useState("");
  const [parsedQ, setParsedQ] = useState([]);
  const [previewPage, setPreviewPage] = useState(0);
  const PREVIEW_PER_PAGE = 20;
  const CATS = ["General","Pharmacology","Physiology","Midwifery","Public Health","Paediatrics","Psychiatric","Critical Care","Anatomy","Medical-Surgical","Community Health","Obstetrics","Paediatrics"];

  const save = async (newPool, titleOverride) => {
    const title = titleOverride !== undefined ? titleOverride : mockTitle;
    setPool(newPool);
    lsSet("nv-daily-mock", newPool);
    lsSet("nv-daily-mock-title", title);
    dispatchSync();
    setSaving(true);
    const ok = await mockChunkSave(newPool, { mockTitle: title });
    setSaving(false);
    if (!ok) toast("⚠️ Saved locally — cloud sync failed","warn");
    else toast(`✅ ${newPool.length} questions saved to cloud!`, "success");
  };

  const addSingle = () => {
    if (!form.q.trim()) return toast("Question text required","error");
    if (!form.options[0]||!form.options[1]) return toast("At least options A & B required","error");
    if (pool.length >= 250 && editIdx===null) return toast("Pool is full (250). Delete some first.","error");
    const q = {id:Date.now(), q:form.q.trim(), options:form.options.map(o=>o.trim()), ans:form.ans, cat:form.cat};
    let np;
    if (editIdx!==null) { np=pool.map((p,i)=>i===editIdx?q:p); setEditIdx(null); }
    else { np=[...pool,q]; }
    save(np);
    setForm({q:"",options:["","","",""],ans:0,cat:"General"});
  };

  const doParse = () => {
    const items = robustParseQuestions(pasteText, pasteAnswers);
    const remaining = 250 - pool.length;
    const capped = items.slice(0, remaining);
    setParsedQ(capped);
    setPreviewPage(0);
    if (!capped.length) toast("No questions parsed — check format below","error");
    else toast(
      `✅ ${capped.length} question${capped.length!==1?"s":""} parsed!`
      + (items.length > capped.length ? ` (${items.length-capped.length} skipped — would exceed 250)` : ""),
      "success"
    );
  };

  const importParsed = async () => {
    if (!parsedQ.length) return;
    const newPool = [...pool, ...parsedQ];
    await save(newPool);
    setParsedQ([]); setPasteText(""); setPasteAnswers(""); setPreviewPage(0);
  };

  const deleteOne = (i) => {
    if (!confirm("Delete this question?")) return;
    const np = pool.filter((_,idx)=>idx!==i);
    save(np);
    if(editIdx===i){ setEditIdx(null); setForm({q:"",options:["","","",""],ans:0,cat:"General"}); }
  };

  const deleteAll = () => {
    if (!confirm(`Delete ALL ${pool.length} questions? This cannot be undone.`)) return;
    save([]);
  };

  const pct = Math.min(100, Math.round((pool.length/250)*100));
  const barColor = pool.length>=250 ? "#ef4444" : pool.length>=200 ? "#fb923c" : "#4a7a2e";

  // Paginated preview
  const previewPages = Math.ceil(parsedQ.length / PREVIEW_PER_PAGE);
  const previewSlice = parsedQ.slice(previewPage*PREVIEW_PER_PAGE, (previewPage+1)*PREVIEW_PER_PAGE);

  return (
    <div>
      {/* Header */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8,flexWrap:"wrap",gap:8}}>
        <div>
          <div style={{fontWeight:800,fontSize:15,color:"#4a7a2e"}}>📅 Daily Mock Question Pool</div>
          <div style={{fontSize:12,color:"var(--text3)",marginTop:2}}>
            {pool.length}/250 questions
            {saving&&<span style={{color:"#4a7a2e",marginLeft:8,fontWeight:700}}>⏳ Saving to cloud…</span>}
          </div>
        </div>
        {pool.length>0&&<button className="btn btn-sm btn-danger" onClick={deleteAll}>🗑️ Delete All</button>}
      </div>

      {/* Capacity bar */}
      <div style={{marginBottom:14}}>
        <div style={{height:8,borderRadius:8,background:"var(--border)",overflow:"hidden"}}>
          <div style={{height:"100%",borderRadius:8,background:barColor,width:`${pct}%`,transition:"width .4s"}}/>
        </div>
        <div style={{display:"flex",justifyContent:"space-between",fontSize:10,color:"var(--text3)",marginTop:3}}>
          <span style={{fontWeight:700,color:barColor}}>{pool.length} loaded</span>
          <span>{250-pool.length} slots remaining</span>
        </div>
      </div>

      {/* Exam title */}
      <div className="card2" style={{marginBottom:14,border:"1px solid #4a7a2e30",padding:"12px 16px"}}>
        <div style={{fontWeight:800,fontSize:13,color:"#4a7a2e",marginBottom:6}}>🏷️ Exam Title (shown to students)</div>
        <div style={{display:"flex",gap:8}}>
          <input className="inp" style={{marginBottom:0,flex:1}} value={mockTitle}
            onChange={e=>setMockTitle(e.target.value)}
            placeholder="e.g. Nursing Council Pre-Exam Mock 2025" />
          <button className="btn btn-accent" style={{background:"linear-gradient(135deg,#4a7a2e,#6aaa40)",border:"none",whiteSpace:"nowrap"}}
            onClick={()=>save(pool,mockTitle)}>💾 Save</button>
        </div>
        {mockTitle&&<div style={{marginTop:5,fontSize:11,color:"#4a7a2e",fontWeight:700}}>✓ "{mockTitle}"</div>}
      </div>

      {/* Mode tabs */}
      <div style={{display:"flex",gap:8,margin:"14px 0 12px",flexWrap:"wrap"}}>
        <button className={`btn btn-sm${mode==="single"?" btn-accent":""}`}
          style={mode==="single"?{background:"#4a7a2e",border:"none"}:{}}
          onClick={()=>{setMode("single");setEditIdx(null);setForm({q:"",options:["","","",""],ans:0,cat:"General"});}}>✏️ Single</button>
        <button className={`btn btn-sm${mode==="paste"?" btn-accent":""}`}
          style={mode==="paste"?{background:"#4a7a2e",border:"none"}:{}}
          onClick={()=>setMode("paste")}>📋 Paste 250 Questions</button>
      </div>

      {/* Single form */}
      {mode==="single"&&(
        <div className="card2" style={{marginBottom:14,border:"1px solid #4a7a2e30"}}>
          <div style={{fontWeight:800,fontSize:13,color:"#4a7a2e",marginBottom:10}}>
            {editIdx!==null?`✏️ Editing Q${editIdx+1}`:"✏️ New Question"}
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr auto",gap:8,marginBottom:8}}>
            <div>
              <label className="lbl">Question *</label>
              <textarea className="inp" rows={3} style={{resize:"vertical"}} value={form.q}
                onChange={e=>setForm({...form,q:e.target.value})} placeholder="Question text..." />
            </div>
            <div>
              <label className="lbl">Category</label>
              <select className="inp" value={form.cat} onChange={e=>setForm({...form,cat:e.target.value})}>
                {CATS.map(c=><option key={c}>{c}</option>)}
              </select>
            </div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:8}}>
            {["A","B","C","D"].map((L,i)=>(
              <div key={L}>
                <label className="lbl">Option {L}{i<2?" *":""}</label>
                <input className="inp" style={{marginBottom:0}} placeholder={`Option ${L}...`} value={form.options[i]}
                  onChange={e=>{const o=[...form.options];o[i]=e.target.value;setForm({...form,options:o});}} />
              </div>
            ))}
          </div>
          <label className="lbl">Correct Answer *</label>
          <select className="inp" value={form.ans} onChange={e=>setForm({...form,ans:+e.target.value})}>
            {["A","B","C","D"].map((L,i)=><option key={L} value={i}>Option {L}{form.options[i]?`: ${form.options[i]}`:""}</option>)}
          </select>
          <div style={{display:"flex",gap:8}}>
            <button className="btn btn-accent" style={{background:"linear-gradient(135deg,#4a7a2e,#6aaa40)",border:"none"}}
              onClick={addSingle}>{editIdx!==null?"💾 Update":"➕ Add to Pool"}</button>
            {editIdx!==null&&<button className="btn" onClick={()=>{setEditIdx(null);setForm({q:"",options:["","","",""],ans:0,cat:"General"});}}>Cancel</button>}
          </div>
        </div>
      )}

      {/* Paste form */}
      {mode==="paste"&&(
        <div className="card2" style={{marginBottom:14,border:"1px solid #4a7a2e30"}}>
          <div style={{fontWeight:800,fontSize:13,color:"#4a7a2e",marginBottom:4}}>📋 Paste Up to 250 Questions</div>
          <div style={{fontSize:11,color:"var(--text3)",marginBottom:10,lineHeight:1.7,background:"var(--bg4)",borderRadius:8,padding:"8px 12px"}}>
            <b>Supported formats (can mix):</b><br/>
            <code>1. Question text</code> or <code>Q: Question text</code><br/>
            <code>A. Option &nbsp; B. Option &nbsp; C. Option &nbsp; D. Option</code><br/>
            <code>Answer: B</code> &nbsp;(inline) — OR use the Answers box on the right<br/>
            Blank lines between questions are <b>optional</b> — parser handles both.
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 260px",gap:12,marginBottom:10}}>
            <div>
              <div style={{fontSize:11,fontWeight:800,color:"#4a7a2e",marginBottom:4}}>📝 Questions (paste all 250 here)</div>
              <textarea className="paste-box" style={{minHeight:260,resize:"vertical"}}
                placeholder={"1. What is the normal adult temperature?\nA. 35.0°C\nB. 36.1–37.2°C\nC. 38.5°C\nD. 40.0°C\nAnswer: B\n2. Which organ produces insulin?\nA. Liver\nB. Kidney\nC. Pancreas\nD. Spleen\nAnswer: C"}
                value={pasteText} onChange={e=>{setPasteText(e.target.value);setParsedQ([]);setPreviewPage(0);}} />
            </div>
            <div>
              <div style={{fontSize:11,fontWeight:800,color:"var(--success)",marginBottom:4}}>✅ Answer Key (optional)<br/><span style={{fontWeight:500,color:"var(--text3)"}}>One per line: A / B / C / D<br/>Only needed if answers aren't<br/>included in the questions box.</span></div>
              <textarea className="paste-box" style={{minHeight:260,resize:"vertical",borderColor:"rgba(34,197,94,.35)"}}
                placeholder={"B\nC\nA\n..."} style={{borderColor:"rgba(34,197,94,.35)",minHeight:260,resize:"vertical"}}
                value={pasteAnswers} onChange={e=>{setPasteAnswers(e.target.value);setParsedQ([]);setPreviewPage(0);}} />
            </div>
          </div>
          <div style={{display:"flex",gap:8,flexWrap:"wrap",alignItems:"center"}}>
            <button className="btn btn-accent" style={{background:"linear-gradient(135deg,#4a7a2e,#6aaa40)",border:"none",fontSize:14,padding:"10px 20px"}}
              onClick={doParse}>🔍 Parse Questions</button>
            {parsedQ.length>0&&(
              <button className="btn btn-success" style={{fontSize:14,padding:"10px 20px"}}
                onClick={importParsed} disabled={saving}>
                {saving?"⏳ Saving…":`✅ Add ${parsedQ.length} to Pool`}
              </button>
            )}
            <button className="btn" onClick={()=>{setParsedQ([]);setPasteText("");setPasteAnswers("");setPreviewPage(0);}}>🗑️ Clear</button>
          </div>

          {/* Parsed preview — paginated so DOM doesn't freeze with 250 items */}
          {parsedQ.length>0&&(
            <div style={{marginTop:12,border:"1px solid var(--success)",borderRadius:8,overflow:"hidden"}}>
              <div style={{padding:"10px 14px",background:"rgba(34,197,94,.1)",display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
                <span style={{fontSize:13,fontWeight:800,color:"var(--success)"}}>✓ {parsedQ.length} questions parsed — review then click "Add to Pool"</span>
                {previewPages>1&&(
                  <div style={{display:"flex",gap:6,alignItems:"center"}}>
                    <button className="btn btn-sm" disabled={previewPage===0} onClick={()=>setPreviewPage(p=>p-1)}>← Prev</button>
                    <span style={{fontSize:11,color:"var(--text3)"}}>Page {previewPage+1}/{previewPages}</span>
                    <button className="btn btn-sm" disabled={previewPage>=previewPages-1} onClick={()=>setPreviewPage(p=>p+1)}>Next →</button>
                  </div>
                )}
              </div>
              {previewSlice.map((p,i)=>{
                const globalI = previewPage*PREVIEW_PER_PAGE + i;
                return (
                  <div key={globalI} style={{padding:"8px 14px",borderTop:"1px solid var(--border)"}}>
                    <div style={{fontWeight:700,fontSize:12,marginBottom:4}}>{globalI+1}. {p.q}</div>
                    <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
                      {p.options.map((opt,oi)=> opt ? (
                        <span key={oi} style={{fontSize:11,padding:"2px 8px",borderRadius:5,
                          background:oi===p.ans?"rgba(34,197,94,.15)":"var(--bg4)",
                          border:`1px solid ${oi===p.ans?"var(--success)":"var(--border)"}`,
                          color:oi===p.ans?"var(--success)":"var(--text3)",fontWeight:oi===p.ans?800:400
                        }}>{"ABCD"[oi]}. {opt}{oi===p.ans?" ✓":""}</span>
                      ) : null)}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      )}

      {/* Pool list — also paginated */}
      {pool.length>0&&(
        <PoolList pool={pool} editIdx={editIdx} setForm={setForm} setEditIdx={setEditIdx} setMode={setMode} deleteOne={deleteOne} />
      )}
      {pool.length===0&&(
        <div style={{textAlign:"center",padding:24,color:"var(--text3)",border:"1px dashed var(--border)",borderRadius:10,fontSize:13}}>
          No questions yet — add above.
        </div>
      )}
    </div>
  );
}

// Paginated pool list (prevents DOM overload with 250 items)
function PoolList({ pool, editIdx, setForm, setEditIdx, setMode, deleteOne }) {
  const [page, setPage] = useState(0);
  const PER_PAGE = 25;
  const pages = Math.ceil(pool.length / PER_PAGE);
  const slice = pool.slice(page*PER_PAGE, (page+1)*PER_PAGE);
  return (
    <div>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10,flexWrap:"wrap",gap:8}}>
        <div style={{fontWeight:800,fontSize:13,color:"var(--text)"}}>📋 Question Pool ({pool.length}/250)</div>
        {pages>1&&(
          <div style={{display:"flex",gap:6,alignItems:"center"}}>
            <button className="btn btn-sm" disabled={page===0} onClick={()=>setPage(p=>p-1)}>← Prev</button>
            <span style={{fontSize:11,color:"var(--text3)"}}>Page {page+1}/{pages} · Q{page*PER_PAGE+1}–{Math.min((page+1)*PER_PAGE,pool.length)}</span>
            <button className="btn btn-sm" disabled={page>=pages-1} onClick={()=>setPage(p=>p+1)}>Next →</button>
          </div>
        )}
      </div>
      {slice.map((q,i)=>{
        const gi = page*PER_PAGE+i;
        return (
          <div key={q.id||gi} className="card2" style={{marginBottom:8,borderLeft:`3px solid ${gi===editIdx?"#4a7a2e":"var(--border)"}`}}>
            <div style={{display:"flex",gap:10,alignItems:"flex-start"}}>
              <div style={{width:28,height:28,borderRadius:7,background:"rgba(74,122,46,.15)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:800,color:"#4a7a2e",flexShrink:0}}>{gi+1}</div>
              <div style={{flex:1}}>
                <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:5,flexWrap:"wrap"}}>
                  <div style={{fontWeight:700,fontSize:13,flex:1}}>{q.q}</div>
                  <span style={{fontSize:10,padding:"2px 7px",borderRadius:5,background:"rgba(74,122,46,.1)",color:"#2d4a1e",fontWeight:700,flexShrink:0}}>{q.cat}</span>
                </div>
                <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
                  {q.options.map((opt,oi)=> opt ? (
                    <span key={oi} style={{fontSize:11,padding:"2px 9px",borderRadius:5,
                      background:oi===q.ans?"rgba(34,197,94,.12)":"transparent",
                      border:`1px solid ${oi===q.ans?"var(--success)":"var(--border)"}`,
                      color:oi===q.ans?"var(--success)":"var(--text3)",fontWeight:oi===q.ans?800:400
                    }}>{"ABCD"[oi]}. {opt}{oi===q.ans?" ✓":""}</span>
                  ) : null)}
                </div>
              </div>
              <div style={{display:"flex",gap:4,flexShrink:0}}>
                <button className="btn btn-sm" onClick={()=>{ setForm({q:q.q,options:[...q.options],ans:q.ans,cat:q.cat||"General"}); setEditIdx(gi); setMode("single"); }}>✏️</button>
                <button className="btn btn-sm btn-danger" onClick={()=>deleteOne(gi)}>🗑️</button>
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ── NC Archive helpers ─────────────────────────────────────────────────────
// Archive entry shape:
// { id, type:"paper"|"osce"|"dailymock", spec, year, paperKey, title, savedAt,
//   questions?:[...], checklists?:[...] }
function useNcArchive() {
  return useSharedData("nv-nc-archive", []);
}

// ── Admin: Archive Manager ─────────────────────────────────────────────────
function AdminNcArchiveManager({ toast }) {
  const [archive, setArchive] = useSharedData("nv-nc-archive", []);

  const saveArchive = async (newArr) => {
    setArchive(newArr);
    const ok = await saveShared("ncArchive", newArr);
    if (!ok) toast("⚠️ Saved locally — sync failed","warn");
  };

  const deleteEntry = (id) => {
    if (!confirm("Remove this entry from archive?")) return;
    saveArchive(archive.filter(e=>e.id!==id));
    toast("Removed from archive","success");
  };

  const deleteAll = () => {
    if (!confirm(`Delete ALL ${archive.length} archive entries? Students will lose access to these.`)) return;
    saveArchive([]);
    toast("🗑️ Archive cleared","success");
  };

  const grouped = archive.reduce((g,e)=>{
    const key = e.spec||"Other";
    if (!g[key]) g[key]=[];
    g[key].push(e);
    return g;
  },{});

  return (
    <div>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:4,flexWrap:"wrap",gap:8}}>
        <div>
          <div style={{fontWeight:800,fontSize:15,color:"var(--accent)"}}>🗄️ NC Exam Archive</div>
          <div style={{fontSize:12,color:"var(--text3)",marginTop:2}}>
            {archive.length} item{archive.length!==1?"s":""} saved · Students can retake or review anytime
          </div>
        </div>
        {archive.length>0&&<button className="btn btn-sm btn-danger" onClick={deleteAll}>🗑️ Delete All</button>}
      </div>

      {archive.length===0&&(
        <div style={{textAlign:"center",padding:28,color:"var(--text3)",border:"1px dashed var(--border)",borderRadius:10,marginTop:14}}>
          <div style={{fontSize:36,marginBottom:8}}>🗄️</div>
          <div style={{fontSize:13}}>No archived items yet.<br/>Use the "Save to Archive" button on any paper or OSCE.</div>
        </div>
      )}

      {Object.entries(grouped).map(([spec, entries])=>(
        <div key={spec} style={{marginTop:14}}>
          <div style={{fontWeight:800,fontSize:13,color:"var(--accent)",marginBottom:8,padding:"4px 0",borderBottom:"1px solid var(--border)"}}>
            {NURSING_EXAM_META[spec]?.icon||"📋"} {NURSING_EXAM_META[spec]?.short||spec}
          </div>
          {entries.map(e=>(
            <div key={e.id} className="card2" style={{marginBottom:8,display:"flex",alignItems:"center",gap:12,flexWrap:"wrap"}}>
              <div style={{fontSize:20}}>{e.type==="osce"?"🩺":e.type==="dailymock"?"📅":"📄"}</div>
              <div style={{flex:1}}>
                <div style={{fontWeight:700,fontSize:13}}>{e.title}</div>
                <div style={{fontSize:11,color:"var(--text3)"}}>
                  {e.type==="osce"?`${e.checklists?.length||0} skills`:e.type==="dailymock"?`${e.questions?.length||0} questions`:`${e.questions?.length||0} questions`}
                  {" · "}Saved {new Date(e.savedAt).toLocaleDateString()}
                </div>
              </div>
              <button className="btn btn-sm btn-danger" onClick={()=>deleteEntry(e.id)}>🗑️</button>
            </div>
          ))}
        </div>
      ))}
    </div>
  );
}

// ── Student: NC Archive View ───────────────────────────────────────────────
function NcArchiveView({ toast, currentUser }) {
  const isUnlockedFull = useNcAccess(currentUser);
  const [unlocked, setUnlocked] = useState(isUnlockedFull);
  const [archive] = useNcArchive();
  const [sel, setSel] = useState(null);
  const [mode, setMode] = useState(null); // "exam"|"review"|"osce"

  if (!unlocked) {
    return (
      <div style={{maxWidth:500,margin:"0 auto"}}>
        <div style={{fontWeight:800,fontSize:15,marginBottom:4,color:"var(--accent)"}}>🗄️ Exam Archive</div>
        <div style={{fontSize:12,color:"var(--text3)",marginBottom:16}}>Past papers saved for unlimited retake — premium feature.</div>
        <NcPaywall currentUser={currentUser} onUnlocked={()=>setUnlocked(true)} toast={toast} />
      </div>
    );
  }

  if (mode==="exam"&&sel) {
    const meta = NURSING_EXAM_META[sel.spec]||{color:"#4a7a2e",icon:"📋",short:sel.spec||"Archive"};
    return <NursingMCQExam toast={toast} currentUser={currentUser}
      paper={{...sel, id:`arc_${sel.id}`, title:sel.title}}
      meta={meta} isUnlocked={true} onBack={()=>{setMode(null);setSel(null);}} />;
  }
  if (mode==="review"&&sel) {
    const meta = NURSING_EXAM_META[sel.spec]||{color:"#4a7a2e",icon:"📋",short:sel.spec||"Archive"};
    return <NursingReviewMode paper={{...sel,title:sel.title}} meta={meta}
      currentUser={currentUser} isUnlocked={true} onBack={()=>{setMode(null);setSel(null);}} />;
  }
  if (mode==="osce"&&sel) {
    const meta = NURSING_EXAM_META[sel.spec]||{color:"#4a7a2e",icon:"🩺",short:sel.spec||"Archive"};
    return <NursingOsceView osce={sel} meta={meta} year={sel.year||""}
      currentUser={currentUser} isUnlocked={true} onBack={()=>{setMode(null);setSel(null);}} />;
  }

  const mcqEntries    = archive.filter(e=>e.type!=="osce");
  const osceEntries   = archive.filter(e=>e.type==="osce");

  if (archive.length===0) return (
    <div style={{textAlign:"center",padding:"56px 20px",color:"var(--text3)"}}>
      <div style={{fontSize:52,marginBottom:12}}>🗄️</div>
      <div style={{fontWeight:700,fontSize:15,marginBottom:6}}>No archived exams yet</div>
      <div style={{fontSize:12}}>Admin will archive exams here for unlimited retake.</div>
    </div>
  );

  return (
    <div>
      <div style={{fontWeight:800,fontSize:15,marginBottom:4,color:"var(--accent)"}}>🗄️ Exam Archive</div>
      <div style={{fontSize:12,color:"var(--text3)",marginBottom:20}}>
        {archive.length} item{archive.length!==1?"s":" "} · Retake anytime · No attempt limit
      </div>

      {mcqEntries.length>0&&(
        <div style={{marginBottom:24}}>
          <div style={{fontWeight:800,fontSize:13,marginBottom:10,color:"var(--text)"}}>📄 MCQ Papers</div>
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            {mcqEntries.map(e=>{
              const meta = NURSING_EXAM_META[e.spec]||{color:"#4a7a2e"};
              return (
                <div key={e.id} className="card" style={{borderLeft:`4px solid ${meta.color}`}}>
                  <div style={{display:"flex",gap:10,alignItems:"flex-start",flexWrap:"wrap"}}>
                    <div style={{flex:1}}>
                      <div style={{fontWeight:800,fontSize:14,marginBottom:3}}>{e.title}</div>
                      <div style={{fontSize:11,color:"var(--text3)"}}>
                        {e.type==="dailymock"?"📅 Daily Mock":"📄 Past Paper"} · {e.questions?.length||0} questions
                        {" · "}🗄️ {new Date(e.savedAt).toLocaleDateString()}
                      </div>
                    </div>
                    <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                      <button className="btn btn-sm btn-accent"
                        style={{background:`linear-gradient(135deg,${meta.color},${meta.color}bb)`,border:"none"}}
                        onClick={()=>{setSel(e);setMode("exam");}}>📝 Take Exam</button>
                      <button className="btn btn-sm" style={{borderColor:meta.color,color:meta.color}}
                        onClick={()=>{setSel(e);setMode("review");}}>📖 Review</button>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {osceEntries.length>0&&(
        <div>
          <div style={{fontWeight:800,fontSize:13,marginBottom:10,color:"var(--text)"}}>🩺 OSCE Checklists</div>
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            {osceEntries.map(e=>{
              const meta = NURSING_EXAM_META[e.spec]||{color:"#0077b6"};
              return (
                <div key={e.id} className="card" style={{borderLeft:`4px solid ${meta.color}`}}>
                  <div style={{display:"flex",gap:10,alignItems:"center",flexWrap:"wrap"}}>
                    <div style={{flex:1}}>
                      <div style={{fontWeight:800,fontSize:14,marginBottom:3}}>{e.title}</div>
                      <div style={{fontSize:11,color:"var(--text3)"}}>🩺 {e.checklists?.length||0} clinical skills · 🗄️ {new Date(e.savedAt).toLocaleDateString()}</div>
                    </div>
                    <button className="btn btn-sm btn-accent"
                      style={{background:`linear-gradient(135deg,${meta.color},${meta.color}bb)`,border:"none"}}
                      onClick={()=>{setSel(e);setMode("osce");}}>🩺 View Checklists</button>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

// ── Daily Mock Exam (questions from admin-managed synced pool) ─────────────
function getDailyMockQuestions(pool) {
  if (!pool || pool.length === 0) return [];
  // Serve ALL questions (up to 250) in a date-seeded shuffle
  const today = new Date();
  const seed = today.getFullYear()*10000 + (today.getMonth()+1)*100 + today.getDate();
  const count = Math.min(250, pool.length);
  const arr = [...pool];
  // Fisher-Yates with deterministic seed
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.abs((seed * (i + 1) * 2654435761) >> 0) % (i + 1);
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr.slice(0, count);
}

function NcDailyMockExam({ toast, currentUser, onBack, isAdmin }) {
  const isUnlockedFull = isAdmin || useNcAccess(currentUser);
  const [pool] = useSharedData("nv-daily-mock", []);
  const mockTitle = ls("nv-daily-mock-title", "");
  const [archive, setArchive] = useSharedData("nv-nc-archive", []);
  const [phase, setPhase] = useState("intro");
  const [answers, setAnswers] = useState([]);
  const [qIdx, setQIdx] = useState(0);
  const [finalAnswers, setFinalAnswers] = useState(null);
  const [unlocked, setUnlocked] = useState(isUnlockedFull);
  const today = new Date().toLocaleDateString("en-GB",{day:"2-digit",month:"long",year:"numeric"});
  const questions = getDailyMockQuestions(pool);

  const saveToArchive = async () => {
    if (!questions.length) return toast("No questions to archive","error");
    const entry = {
      id: `arc_dm_${Date.now()}`,
      type: "dailymock",
      spec: "general",
      title: `Daily Mock — ${today}`,
      savedAt: Date.now(),
      questions,
    };
    const newArc = [...archive.filter(e=>e.title!==entry.title), entry];
    setArchive(newArc);
    const ok = await saveShared("ncArchive", newArc);
    toast(ok?"✅ Daily Mock saved to archive!":"⚠️ Saved locally — sync failed", ok?"success":"warn");
  };

  const submit = () => {
    setFinalAnswers([...answers]);
    setPhase("result");
    const score = questions.reduce((s,q,i)=>answers[i]===q.ans?s+1:s,0);
    const results = ls("nv-results",[]);
    saveMyData("results","nv-results",[...results,{id:Date.now(),subject:`Daily Mock — ${today}`,type:"NC Daily Mock",score,total:questions.length,pct:Math.round(score/questions.length*100),date:new Date().toLocaleDateString()}]);
    toast("Daily mock submitted! 🎉","success");
  };

  if (pool.length === 0) return (
    <div style={{textAlign:"center",padding:"56px 20px",color:"var(--text3)"}}>
      <div style={{fontSize:52,marginBottom:12}}>📅</div>
      <div style={{fontWeight:700,fontSize:15,marginBottom:6,color:"#2d4a1e"}}>No Questions Yet</div>
      <div style={{fontSize:12,marginBottom:16}}>Admin hasn't added daily mock questions yet. Check back soon!</div>
      <button className="nc-btn" onClick={onBack}>← Back</button>
    </div>
  );

  // Gate daily mock mid-exam: first NC_MOCK_FREE_LIMIT (15) questions are free,
  // then show paywall to continue — same pattern as specialty papers
  if (!unlocked && !isAdmin && phase === "exam" && qIdx >= NC_MOCK_FREE_LIMIT) {
    const preview = (
      <div>
        {questions.slice(0, NC_MOCK_FREE_LIMIT).map((q, i) => (
          <div key={i} className="nc-card" style={{marginBottom:6,opacity:.7,borderLeft:"3px solid #4a7a2e"}}>
            <div style={{fontWeight:700,fontSize:12,color:"#2d4a1e"}}>Q{i+1}. {q.q}</div>
          </div>
        ))}
      </div>
    );
    return (
      <div style={{maxWidth:500,margin:"0 auto"}}>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:16}}>
          <button className="nc-btn" onClick={onBack}>← Back</button>
          <div style={{fontWeight:800,fontSize:16,color:"#2d4a1e"}}>📅 {mockTitle || "Daily Mock Exam"}</div>
        </div>
        <NcPaywall currentUser={currentUser} onUnlocked={()=>setUnlocked(true)} toast={toast} preview={preview} isMock />
      </div>
    );
  }

  if (phase==="intro") return (
    <div style={{maxWidth:600,margin:"0 auto"}}>
      <div className="nc-card" style={{textAlign:"center",padding:"32px 28px"}}>
        <div style={{fontSize:52,marginBottom:10}}>📅</div>
        <div style={{fontWeight:800,fontSize:22,color:"#2d4a1e",marginBottom:4}}>{mockTitle || "Daily Mock Exam"}</div>
        <div style={{fontSize:13,color:"#6b8a52",marginBottom:20}}>{today} · {questions.length} Questions · Mixed Specialties</div>
        {!isUnlockedFull && (
          <div style={{padding:"8px 14px",borderRadius:9,marginBottom:16,background:"rgba(251,146,60,.1)",border:"1px solid rgba(251,146,60,.3)",fontSize:12,color:"#c05621",fontWeight:700,textAlign:"center"}}>
            ⚠️ Free preview: first {NC_MOCK_FREE_LIMIT} questions — enter a production code to unlock all {questions.length}
          </div>
        )}
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10,marginBottom:24}}>
          {[{icon:"❓",label:`${questions.length} Questions`},{icon:"⏱",label:"No time limit"},{icon:"📊",label:"Score tracked"}].map((s,i)=>(
            <div key={i} style={{background:"rgba(74,122,46,.07)",borderRadius:10,padding:"12px 8px",textAlign:"center"}}>
              <div style={{fontSize:22,marginBottom:3}}>{s.icon}</div>
              <div style={{fontSize:11,fontWeight:700,color:"#2d4a1e"}}>{s.label}</div>
            </div>
          ))}
        </div>
        {isAdmin&&(
          <button className="btn btn-sm" style={{marginBottom:16,borderColor:"#4a7a2e",color:"#4a7a2e"}} onClick={saveToArchive}>
            🗄️ Save Today's Mock to Archive
          </button>
        )}
        <div style={{display:"flex",gap:10}}>
          <button className="nc-btn" style={{flex:1}} onClick={onBack}>← Back</button>
          <button className="nc-btn nc-btn-primary" style={{flex:2,fontSize:15}} onClick={()=>{setAnswers(Array(questions.length).fill(null));setQIdx(0);setPhase("exam");}}>▶ Start Daily Mock</button>
        </div>
      </div>
    </div>
  );

  if (phase==="result") {
    const score = questions.reduce((s,q,i)=>finalAnswers[i]===q.ans?s+1:s,0);
    const pct = Math.round(score/questions.length*100);
    return (
      <div style={{maxWidth:640,margin:"0 auto"}}>
        <div className="nc-card" style={{textAlign:"center",marginBottom:20}}>
          <div style={{fontSize:48,marginBottom:6}}>{pct>=80?"🎉":pct>=60?"👍":"📚"}</div>
          <div style={{fontWeight:800,fontSize:20,color:"#2d4a1e",marginBottom:4}}>{mockTitle || "Daily Mock"} — Complete!</div>
          <div style={{fontWeight:800,fontSize:52,color:pct>=70?"#4a7a2e":pct>=50?"#c05621":"#991b1b",lineHeight:1}}>{score}/{questions.length}</div>
          <div style={{fontSize:16,color:"#6b8a52",marginBottom:10}}>{pct}% — {pct>=80?"Excellent":pct>=60?"Good Pass":pct>=40?"Borderline":"Needs Improvement"}</div>
          <div className="nc-progress-wrap" style={{maxWidth:300,margin:"0 auto 16px"}}>
            <div className="nc-progress-fill" style={{width:`${pct}%`}} />
          </div>
          {isAdmin&&(
            <button className="btn btn-sm" style={{borderColor:"#4a7a2e",color:"#4a7a2e",marginBottom:8}} onClick={saveToArchive}>
              🗄️ Save to Archive
            </button>
          )}
        </div>
        <div style={{fontWeight:800,fontSize:14,color:"#2d4a1e",marginBottom:10}}>📋 Answer Review</div>
        {questions.map((q,i)=>{
          const correct = finalAnswers[i]===q.ans;
          return (
            <div key={i} className="nc-card" style={{marginBottom:10,borderLeft:`4px solid ${finalAnswers[i]===null?"#d4c9a8":correct?"#22c55e":"#ef4444"}`}}>
              <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:8}}>
                <span style={{fontSize:16}}>{finalAnswers[i]===null?"⬜":correct?"✅":"❌"}</span>
                <div style={{fontWeight:700,fontSize:13,flex:1}}>{i+1}. {q.q}</div>
                <span style={{fontSize:10,padding:"2px 7px",borderRadius:5,background:"rgba(74,122,46,.1)",color:"#2d4a1e",fontWeight:700}}>{q.cat}</span>
              </div>
              <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
                {q.options.map((opt,oi)=>(
                  <span key={oi} style={{fontSize:11,padding:"3px 9px",borderRadius:6,
                    background:oi===q.ans?"rgba(34,197,94,.15)":oi===finalAnswers[i]&&!correct?"rgba(239,68,68,.1)":"transparent",
                    border:`1px solid ${oi===q.ans?"#22c55e":oi===finalAnswers[i]&&!correct?"#ef4444":"#d4c9a8"}`,
                    color:oi===q.ans?"#15803d":oi===finalAnswers[i]&&!correct?"#dc2626":"#6b8a52",fontWeight:oi===q.ans?800:400
                  }}>{"ABCD"[oi]}. {opt}{oi===q.ans?" ✓":""}{oi===finalAnswers[i]&&oi!==q.ans?" ✗":""}</span>
                ))}
              </div>
            </div>
          );
        })}
        <div style={{textAlign:"center",marginTop:16}}>
          <button className="nc-btn" onClick={onBack}>← Back to NC Exams</button>
        </div>
      </div>
    );
  }

  const q = questions[qIdx];
  const answeredCount = answers.filter(a=>a!==null).length;
  return (
    <div style={{maxWidth:620,margin:"0 auto"}}>
      <div className="nc-card" style={{marginBottom:14}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:10,flexWrap:"wrap"}}>
          <div>
            <div style={{fontWeight:800,fontSize:15,color:"#2d4a1e"}}>📅 {mockTitle || "Daily Mock"} — {today}</div>
            <div style={{fontSize:11,color:"#6b8a52"}}>{answeredCount}/{questions.length} answered</div>
          </div>
          <button className="nc-btn nc-btn-primary" onClick={()=>{if(confirm("Submit exam now?"))submit();}}>Submit ✓</button>
        </div>
      </div>
      {!unlocked && !isAdmin && (
        <div style={{padding:"6px 12px",borderRadius:8,marginBottom:10,background:"rgba(251,146,60,.1)",border:"1px solid rgba(251,146,60,.3)",fontSize:12,color:"#c05621",fontWeight:700,display:"flex",alignItems:"center",gap:6}}>
          ⚠️ Free preview: {NC_MOCK_FREE_LIMIT} of {questions.length} questions — <span style={{textDecoration:"underline",cursor:"pointer"}} onClick={()=>setQIdx(NC_MOCK_FREE_LIMIT)}>🔓 Unlock all</span>
        </div>
      )}
      <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:12}}>
        {questions.map((_,i)=>{
          const isLocked = !unlocked && !isAdmin && i >= NC_MOCK_FREE_LIMIT;
          return isLocked ? (
            <div key={i} onClick={()=>setQIdx(NC_MOCK_FREE_LIMIT)}
              style={{width:30,height:30,borderRadius:7,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",fontSize:12,
                background:"#f5f0e8",border:"2px dashed #d4c9a8",color:"#6b8a52"}}>🔒</div>
          ) : (
            <div key={i} onClick={()=>setQIdx(i)} style={{width:30,height:30,borderRadius:7,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",fontSize:11,fontWeight:700,transition:"all .15s",
              background:i===qIdx?"#4a7a2e":answers[i]!==null?"rgba(34,197,94,.15)":"#f5f0e8",
              border:`2px solid ${i===qIdx?"#4a7a2e":answers[i]!==null?"#22c55e":"#d4c9a8"}`,
              color:i===qIdx?"white":answers[i]!==null?"#15803d":"#6b8a52"}}>{i+1}</div>
          );
        })}
      </div>
      <div className="nc-progress-wrap" style={{marginBottom:14}}>
        <div className="nc-progress-fill" style={{width:`${(answeredCount/questions.length)*100}%`}} />
      </div>
      <div style={{fontSize:10,color:"#6b8a52",marginBottom:4}}>Question {qIdx+1} of {questions.length} · <span style={{background:"rgba(74,122,46,.1)",borderRadius:4,padding:"1px 5px",color:"#2d4a1e",fontWeight:700}}>{q.cat}</span></div>
      <div className="nc-card" style={{marginBottom:12}}>
        <div style={{fontWeight:700,fontSize:16,lineHeight:1.6,color:"#1a2e0a"}}>{q.q}</div>
      </div>
      {q.options.map((opt,i)=>(
        <div key={i} onClick={()=>setAnswers(prev=>{const n=[...prev];n[qIdx]=i;return n;})}
          className={`nc-quiz-opt${answers[qIdx]===i?" selected":""}`}>
          <span style={{fontSize:11,opacity:.7,marginRight:6}}>{"ABCD"[i]}.</span>{opt}
          {answers[qIdx]===i&&<span style={{float:"right",color:"#4a7a2e",fontWeight:800}}>✓</span>}
        </div>
      ))}
      <div style={{display:"flex",gap:8,marginTop:14,justifyContent:"space-between"}}>
        <button className="nc-btn" disabled={qIdx===0} onClick={()=>setQIdx(q=>q-1)}>← Prev</button>
        {qIdx<questions.length-1
          ?<button className="nc-btn nc-btn-primary" onClick={()=>setQIdx(q=>q+1)}>Next →</button>
          :<button className="nc-btn nc-btn-primary" onClick={()=>{if(confirm("Submit exam?"))submit();}}>Submit ✓</button>
        }
      </div>
    </div>
  );
}


